from typing import Optional, Tuple
def solve(arr: list[int], target: int) -> Optional[Tuple[int,int]]:
    seen: dict[int,int] = {}
    for i, x in enumerate(arr):
        need = target - x
        if need in seen: return (seen[need], i)
        seen[x] = i
    return None

