# C0699 · Background job / queue
from fastapi import FastAPI, BackgroundTasks

app = FastAPI()

def do_work(task_id: str):
    # tarea background
    with open("jobs.log","a",encoding="utf-8") as f:
        f.write(f"done {task_id}\n")

@app.post("/jobs/{task_id}", status_code=202)
def enqueue(task_id: str, bg: BackgroundTasks):
    bg.add_task(do_work, task_id)
    return {"status":"queued","id":task_id}
